.darma-loader-darma-custom-190 {
  color: #e11d48;
height: 15px;
aspect-ratio: 6;
display: flex;
}
.darma-loader-darma-custom-190:before,
.darma-loader-darma-custom-190:after {
content: "";
flex: 1;
padding-left: calc(100%/6);
background: radial-gradient(closest-side at calc(100%/3) 50%,currentColor 90%,#0000) 0/75% 100% content-box;
animation: darma-loader-darma-custom-190-l20 2s infinite;
}
.darma-loader-darma-custom-190:after {
--_s:-1;
}
@keyframes darma-loader-darma-custom-190-l20 {
0% {transform:scale(var(--_s,1)) translate(0) rotate(0)}
25% {transform:scale(var(--_s,1)) translate(-25%) rotate(0)}
50% {transform:scale(var(--_s,1)) translate(-25%) rotate(1turn)}
75%,100% {transform:scale(var(--_s,1)) translate(0) rotate(1turn)}
}

